// Formato A3 Asesor (Wolters Kluwer)
// Campos separados por tabulador, codificación ANSI
const facturas = $('Leer Facturas PostgreSQL').all().map(i => i.json);
const body = $('Webhook').first().json.body || {};
const codigoEmpresa = body.codigo_empresa || 'KONTIA';
const ejercicio = body.ejercicio || new Date().getFullYear().toString();

const lineas = [];

// Cabecera del fichero
// Formato: TipoReg|Ejercicio|Diario|Asiento|Fecha|Cuenta|Debe|Haber|Concepto|NIF|Factura

let numAsiento = 1;

for (const f of facturas) {
  const fecha = (f.fecha_factura || '').replace(/-/g, '');
  const esCompra = (f.tipo_documento || 'compra') !== 'venta';
  const base = Number(f.base_imponible) || Number(f.total_factura) || 0;
  const iva = Number(f.cuota_iva) || 0;
  const retencion = Number(f.cuota_retencion) || 0;
  const total = Number(f.total_factura) || 0;
  const cuentaGasto = f.cuenta_gasto || '629';
  const nif = f.nif_emisor || '';
  const concepto = (f.nombre_emisor || '') + ' ' + (f.numero_factura || '');
  const numFra = f.numero_factura || '';

  if (esCompra) {
    // Línea 1: Gasto (Debe)
    lineas.push([
      'A', ejercicio, 'COM', String(numAsiento).padStart(6,'0'),
      fecha, cuentaGasto.padEnd(10,' '),
      base.toFixed(2), '0.00', concepto.substring(0,40), nif, numFra
    ].join('\t'));

    // Línea 2: IVA Soportado (Debe)
    if (iva > 0) {
      lineas.push([
        'A', ejercicio, 'COM', String(numAsiento).padStart(6,'0'),
        fecha, '4720000000',
        iva.toFixed(2), '0.00', 'IVA ' + concepto.substring(0,36), nif, numFra
      ].join('\t'));
    }

    // Línea 3: Retención (Haber) si existe
    if (retencion > 0) {
      lineas.push([
        'A', ejercicio, 'COM', String(numAsiento).padStart(6,'0'),
        fecha, '4751000000',
        '0.00', retencion.toFixed(2), 'RET ' + concepto.substring(0,36), nif, numFra
      ].join('\t'));
    }

    // Línea 4: Proveedor (Haber)
    lineas.push([
      'A', ejercicio, 'COM', String(numAsiento).padStart(6,'0'),
      fecha, '4000000001',
      '0.00', total.toFixed(2), concepto.substring(0,40), nif, numFra
    ].join('\t'));
  } else {
    // Venta: Cliente (Debe) / Ingreso (Haber) / IVA Repercutido (Haber)
    lineas.push([
      'A', ejercicio, 'VEN', String(numAsiento).padStart(6,'0'),
      fecha, '4300000001',
      total.toFixed(2), '0.00', concepto.substring(0,40), nif, numFra
    ].join('\t'));

    lineas.push([
      'A', ejercicio, 'VEN', String(numAsiento).padStart(6,'0'),
      fecha, (cuentaGasto || '7050000000').padEnd(10,' '),
      '0.00', base.toFixed(2), concepto.substring(0,40), nif, numFra
    ].join('\t'));

    if (iva > 0) {
      lineas.push([
        'A', ejercicio, 'VEN', String(numAsiento).padStart(6,'0'),
        fecha, '4770000000',
        '0.00', iva.toFixed(2), 'IVA ' + concepto.substring(0,36), nif, numFra
      ].join('\t'));
    }
  }
  numAsiento++;
}

const csv = lineas.join('\n');
return [{
  json: {
    success: true,
    total_facturas: facturas.length,
    total_asientos: numAsiento - 1,
    formato: 'A3',
    csv_content: csv,
    filename: 'kontia_a3_' + ejercicio + '_' + new Date().toISOString().split('T')[0] + '.txt'
  }
}];
